import { getFromProps } from '../../helpers/getFromProps.js';
import { css } from 'styled-components';

const fromProps = getFromProps();
const dividerCss = css `
  padding: 0;
  display: flex;
  background: ${fromProps('color')};
  
  ${({ direction }) => (direction === 'horizontal'
    ? css `
        margin-top: 0;
        margin-bottom: 0;
        width: 100%;
        height: 1px;
      `
    : css `
        margin-left: 0;
        margin-right: 0;
        width: 1px;
      `)}
`;

export { dividerCss };
